#include <stdio.h>
#include <stdlib.h>

// Function to perform DFS and store nodes in stack by finishing time
void dfs(int node, int *vis, int **adj, int *st, int *top) {
    vis[node] = 1;
    for (int i = 0; i < adj[node][0]; i++) {
        if (!vis[adj[node][i + 1]]) {
            dfs(adj[node][i + 1], vis, adj, st, top);
        }
    }
    st[(*top)++] = node;
}

// Function to perform DFS on transposed graph
void dfs3(int node, int *vis, int **adjT) {
    vis[node] = 1;
    for (int i = 0; i < adjT[node][0]; i++) {
        if (!vis[adjT[node][i + 1]]) {
            dfs3(adjT[node][i + 1], vis, adjT);
        }
    }
}

// Function to find number of strongly connected components
int kosaraju(int V, int **adj) {
    int *vis = (int *)malloc(V * sizeof(int));
    int *st = (int *)malloc(V * sizeof(int));
    int top = 0;

    // Step 1: Do DFS to fill stack
    for (int i = 0; i < V; i++) {
        vis[i] = 0;
    }
    for (int i = 0; i < V; i++) {
        if (!vis[i]) {
            dfs(i, vis, adj, st, &top);
        }
    }

    // Step 2: Build transpose graph
    int **adjT = (int **)malloc(V * sizeof(int *));
    for (int i = 0; i < V; i++) {
        adjT[i] = (int *)malloc((adj[i][0] + 1) * sizeof(int));
        adjT[i][0] = 0;
    }
    for (int i = 0; i < V; i++) {
        for (int j = 0; j < adj[i][0]; j++) {
            adjT[adj[i][j + 1]][0]++;
            adjT[adj[i][j + 1]][adjT[adj[i][j + 1]][0]] = i;
        }
    }

    // Step 3: Process stack to count SCCs
    int scc = 0;
    for (int i = 0; i < V; i++) {
        vis[i] = 0;
    }
    while (top > 0) {
        int node = st[--top];
        if (!vis[node]) {
            scc++;
            dfs3(node, vis, adjT);
        }
    }
    return scc;
}

int main() {
    int V, E;
    scanf("%d %d", &V, &E);
    int **adj = (int **)malloc(V * sizeof(int *));
    for (int i = 0; i < V; i++) {
        adj[i] = (int *)malloc((E + 1) * sizeof(int));
        adj[i][0] = 0;
    }
    for (int i = 0; i < E; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        adj[u][0]++;
        adj[u][adj[u][0]] = v;
    }
    int ans = kosaraju(V, adj);
    printf("The number of strongly connected components is: %d\n", ans);
    return 0;
}

